1	type Item = { type: string; cursed?: boolean };
2	type Scenario = { steps: Array<{ op: string; items: Array<Item> }> };
3	
4	const PROCESSING_FEE = 5;
5	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
6	
7	const BASE_PREMIUMS: Record<string, number> = {
8	  sword: 100,
9	  amulet: 60,
10	  staff: 80,
11	  potion: 40,
12	  rune: 25,
13	  moonstone: 25,
14	};
15	
16	function withFirstInsuranceSurcharge(basePremium: number): number {
17	  return basePremium + basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
18	}
19	
20	function quoteItem(item: Item): number {
21	  const basePremium = BASE_PREMIUMS[item.type];
22	  const cursedSurcharge = item.cursed ? basePremium * 0.5 : 0;
23	  return withFirstInsuranceSurcharge(basePremium) + cursedSurcharge;
24	}
25	
26	const COMPONENT_TYPES = ["rune", "moonstone"];
27	const BLOCK_OF_THREE_BASE = 60;
28	
29	function countByType(items: Array<Item>): Record<string, number> {
30	  const counts: Record<string, number> = {};
31	  for (const item of items) {
32	    counts[item.type] = (counts[item.type] ?? 0) + 1;
33	  }
34	  return counts;
35	}
36	
37	export function processScenario(scenario: unknown): { results: Array<{ premium?: number }> } {
38	  const { steps } = scenario as Scenario;
39	  const items = steps[0].items;
40	  const counts = countByType(items);
41	
42	  let itemsPremium = 0;
43	  const bundledTypes = new Set<string>();
44	  for (const componentType of COMPONENT_TYPES) {
45	    if (counts[componentType] === 3) {
46	      itemsPremium += withFirstInsuranceSurcharge(BLOCK_OF_THREE_BASE);
47	      bundledTypes.add(componentType);
48	    }
49	  }
50	
51	  for (const item of items) {
52	    if (bundledTypes.has(item.type)) continue;
53	    itemsPremium += quoteItem(item);
54	  }
55	
56	  const premium = Math.ceil(itemsPremium + PROCESSING_FEE);
57	  return { results: [{ premium }] };
58	}
